function flatten(arr) {
  const out = [];
  for (const x of arr) Array.isArray(x) ? out.push(...flatten(x)) : out.push(x);
  return out;
}

function throttle(fn, ms) {
  let last = 0;
  return function (...args) {
    const now = Date.now();
    if (now - last >= ms) {
      last = now;
      fn.apply(this, args);
    }
  };
}

